import { UserNavigation } from "@/components/molecules"
import { retrieveCustomer } from "@/lib/data/customer"
import { redirect } from "next/navigation"

interface UserPageProps {
  searchParams: Promise<{
    error?: string
    provider?: string
    message?: string
  }>
}

export default async function UserPage({ searchParams }: UserPageProps) {
  const params = await searchParams

  // If there are OAuth error params, redirect to /login with them preserved
  if (params.error) {
    const loginParams = new URLSearchParams()
    if (params.error) loginParams.set("error", params.error)
    if (params.provider) loginParams.set("provider", params.provider)
    if (params.message) loginParams.set("message", params.message)
    redirect(`/login?${loginParams.toString()}`)
  }

  const user = await retrieveCustomer()

  if (!user) {
    redirect("/login")
  }

  return (
    <main className="max-w-[1200px] mx-auto px-6 md:px-12 py-8">
      <div className="grid grid-cols-1 md:grid-cols-[240px_1fr] gap-8">
        <UserNavigation />
        <div>
          <h1
            className="font-barlow-condensed font-bold"
            style={{ fontSize: 28, color: "var(--text-primary, #F0EEFF)", letterSpacing: "-0.01em" }}
          >
            Welcome {user.first_name}
          </h1>
          <p style={{ fontSize: 15, color: "var(--text-secondary, #B8B0D8)", marginTop: 4 }}>
            Your account is ready to go!
          </p>
        </div>
      </div>
    </main>
  )
}

"use server"

import { sdk } from "../config"
import { HttpTypes } from "@medusajs/types"
import { revalidateTag } from "next/cache"
import { redirect } from "next/navigation"
import {
  getAuthHeaders,
  getCacheOptions,
  getCacheTag,
  getCartId,
  removeAllAuthCookies,
  removeCartId,
  setAuthToken,
} from "./cookies"

export const retrieveCustomer =
  async (): Promise<HttpTypes.StoreCustomer | null> => {
    const authHeaders = await getAuthHeaders()

    if (!authHeaders || !('authorization' in authHeaders)) {
      return null
    }

    const headers = {
      ...authHeaders,
    }

    const next = {
      ...(await getCacheOptions("customers")),
    }

    return await sdk.client
      .fetch<{ customer: HttpTypes.StoreCustomer }>(`/store/customers/me`, {
        method: "GET",
        query: {
          fields: "*orders",
        },
        headers,
        next,
        cache: "force-cache",
      })
      .then(({ customer }) => customer)
      .catch(() => null)
  }

export interface CustomerProfile {
  customer_id: string
  display_name: string | null
  bio: string | null
  location: string | null
  avatar_url: string | null
  tcg_games: string[] | null
  notify_order_updates: boolean
  notify_price_alerts: boolean
  notify_messages: boolean
  profile_public: boolean
  show_sales_history: boolean
  is_seller: boolean
}

export async function invalidateCustomerProfileCache() {
  revalidateTag('customer-profile')
}

export const getCustomerProfile = async (customerId: string): Promise<CustomerProfile | null> => {
  try {
    const res = await fetch(
      `${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/customers/${customerId}/profile`,
      { next: { tags: ['customer-profile'], revalidate: 60 } }
    )
    if (!res.ok) return null
    const { data } = await res.json()
    return data as CustomerProfile
  } catch {
    return null
  }
}

export const updateCustomer = async (body: HttpTypes.StoreUpdateCustomer) => {
  const headers = {
    ...(await getAuthHeaders()),
  }

  const updateRes = await sdk.store.customer
    .update(body, {}, headers)
    .then(({ customer }) => customer)
    .catch((err) => {
      throw new Error(err.message)
    })

  const cacheTag = await getCacheTag("customers")
  revalidateTag(cacheTag)

  return updateRes
}

export async function signup(formData: FormData) {
  const password = formData.get("password") as string
  const customerForm = {
    email: formData.get("email") as string,
    first_name: formData.get("first_name") as string,
    last_name: formData.get("last_name") as string,
    phone: formData.get("phone") as string,
  }

  try {
    const token = await sdk.auth.register("customer", "emailpass", {
      email: customerForm.email,
      password: password,
    })

    await setAuthToken(token as string)

    const headers = {
      ...(await getAuthHeaders()),
    }

    const { customer: createdCustomer } = await sdk.store.customer.create(
      customerForm,
      {},
      headers
    )

    const loginToken = await sdk.auth.login("customer", "emailpass", {
      email: customerForm.email,
      password,
    })

    await setAuthToken(loginToken as string)

    // Trigger post-registration side effects: verification email + refresh token + auth event
    const backendUrl = process.env.MEDUSA_BACKEND_URL || 'http://localhost:9000'
    const authHeaders = await getAuthHeaders()
    const postRegisterRes = await fetch(
      `${backendUrl}/store/auth/emailpass/post-register`,
      {
        method: 'POST',
        headers: { ...(authHeaders as Record<string, string>) },
      }
    )
    if (postRegisterRes.ok) {
      // Propagate the refresh token Set-Cookie header to the client
      const refreshCookie = postRegisterRes.headers.get('set-cookie')
      if (refreshCookie) {
        const { cookies } = await import('next/headers')
        const cookieStore = await cookies()
        const match = refreshCookie.match(/_medusa_refresh=([^;]+)/)
        if (match) {
          cookieStore.set('_medusa_refresh', match[1], {
            httpOnly: true,
            secure: process.env.NODE_ENV === 'production',
            sameSite: 'strict',
            maxAge: 30 * 24 * 60 * 60,
            path: '/',
          })
        }
      }
    }

    const customerCacheTag = await getCacheTag("customers")
    revalidateTag(customerCacheTag)

    await transferCart()

    return createdCustomer
  } catch (error: any) {
    return error.toString()
  }
}

export async function login(formData: FormData) {
  const email = formData.get("email") as string
  const password = formData.get("password") as string

  try {
    await sdk.auth
      .login("customer", "emailpass", { email, password })
      .then(async (token) => {
        await setAuthToken(token as string)
        const customerCacheTag = await getCacheTag("customers")
        revalidateTag(customerCacheTag)
      })
  } catch (error: any) {
    // Check if this might be a seller account trying to login
    try {
      await sdk.auth.login("seller", "emailpass", { email, password })
      // If seller login succeeds, return a specific error message
      return "This email is registered as a seller account. Please create a separate customer account to shop on the storefront, or use the vendor panel to manage your store."
    } catch (sellerError) {
      // If both customer and seller login fail, return the original customer error
      return error.toString()
    }
  }

  try {
    await transferCart()
  } catch (error: any) {
    return error.toString()
  }
}

/**
 * Clears all auth state (cookies, caches) without redirecting.
 * Use this in API route handlers where redirect() would throw.
 */
export async function clearSession() {
  try {
    const authHeaders = await getAuthHeaders()

    if (authHeaders && 'authorization' in authHeaders) {
      const bearerToken = (authHeaders as any).authorization

      await fetch(`${process.env.MEDUSA_BACKEND_URL || 'http://localhost:9000'}/auth/logout`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": bearerToken
        }
      }).catch(() => {
        // Logout API call failed — non-critical
      })
    }
  } catch {
    // Error during logout — non-critical
  }

  await removeAllAuthCookies()

  const customerCacheTag = await getCacheTag("customers")
  revalidateTag(customerCacheTag)

  await removeCartId()

  const cartCacheTag = await getCacheTag("carts")
  revalidateTag(cartCacheTag)
}

export async function signout() {
  await clearSession()
  redirect(`/`)
}

export async function transferCart() {
  const cartId = await getCartId()

  if (!cartId) {
    return
  }

  const headers = await getAuthHeaders()

  await sdk.store.cart.transferCart(cartId, {}, headers)

  const cartCacheTag = await getCacheTag("carts")
  revalidateTag(cartCacheTag)
}

export const addCustomerAddress = async (formData: FormData): Promise<any> => {
  const address = {
    address_name: formData.get("address_name") as string,
    first_name: formData.get("first_name") as string,
    last_name: formData.get("last_name") as string,
    company: formData.get("company") as string,
    address_1: formData.get("address_1") as string,
    city: formData.get("city") as string,
    postal_code: formData.get("postal_code") as string,
    country_code: formData.get("country_code") as string,
    phone: formData.get("phone") as string,
    province: formData.get("province") as string,
    is_default_billing: Boolean(formData.get("isDefaultBilling")),
    is_default_shipping: Boolean(formData.get("isDefaultShipping")),
  }

  const headers = {
    ...(await getAuthHeaders()),
  }

  return sdk.store.customer
    .createAddress(address, {}, headers)
    .then(async ({ customer }) => {
      const customerCacheTag = await getCacheTag("customers")
      revalidateTag(customerCacheTag)
      return { success: true, error: null }
    })
    .catch((err) => {
      return { success: false, error: err.toString() }
    })
}

export const deleteCustomerAddress = async (
  addressId: string
): Promise<void> => {
  const headers = {
    ...(await getAuthHeaders()),
  }

  await sdk.store.customer
    .deleteAddress(addressId, headers)
    .then(async () => {
      const customerCacheTag = await getCacheTag("customers")
      revalidateTag(customerCacheTag)
      return { success: true, error: null }
    })
    .catch((err) => {
      return { success: false, error: err.toString() }
    })
}

export const updateCustomerAddress = async (
  formData: FormData
): Promise<any> => {
  const addressId = formData.get("addressId") as string

  if (!addressId) {
    return { success: false, error: "Address ID is required" }
  }

  const address = {
    address_name: formData.get("address_name") as string,
    first_name: formData.get("first_name") as string,
    last_name: formData.get("last_name") as string,
    company: formData.get("company") as string,
    address_1: formData.get("address_1") as string,
    address_2: formData.get("address_2") as string,
    city: formData.get("city") as string,
    postal_code: formData.get("postal_code") as string,
    province: formData.get("province") as string,
    country_code: formData.get("country_code") as string,
  } as HttpTypes.StoreUpdateCustomerAddress

  const phone = formData.get("phone") as string

  if (phone) {
    address.phone = phone
  }

  const headers = {
    ...(await getAuthHeaders()),
  }

  return sdk.store.customer
    .updateAddress(addressId, address, {}, headers)
    .then(async () => {
      const customerCacheTag = await getCacheTag("customers")
      revalidateTag(customerCacheTag)
      return { success: true, error: null }
    })
    .catch((err) => {
      return { success: false, error: err.toString() }
    })
}

export const updateCustomerPassword = async (
  password: string,
  token: string
): Promise<any> => {
  const res = await fetch(
    `${process.env.MEDUSA_BACKEND_URL}/auth/customer/emailpass/update`,
    {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify({ password }),
    }
  )
    .then(async () => {
      await removeAllAuthCookies()
      const customerCacheTag = await getCacheTag("customers")
      revalidateTag(customerCacheTag)
      return { success: true, error: null }
    })
    .catch((err: any) => {
      return { success: false, error: err.toString() }
    })

  return res
}

export const sendResetPasswordEmail = async (email: string) => {
  const res = await sdk.auth
    .resetPassword("customer", "emailpass", {
      identifier: email,
    })
    .then(() => {
      return { success: true, error: null }
    })
    .catch((err: any) => {
      return { success: false, error: err.toString() }
    })

  return res
}

export async function loginWithOAuth(
  provider: string,
  authData: { code: string; state: string }
): Promise<{ success: boolean; error?: string }> {
  try {
    const token = await sdk.auth.login("customer", provider, authData)
    
    if (token) {
      await setAuthToken(token as string)
      
      const customerCacheTag = await getCacheTag("customers")
      revalidateTag(customerCacheTag)
      
      // Transfer any existing cart to the authenticated user
      await transferCart()
      
      return { success: true }
    }
    
    return { success: false, error: "Failed to authenticate with OAuth provider" }
  } catch (error: any) {
    console.error("OAuth login error:", error)
    return { 
      success: false, 
      error: error.message || "OAuth authentication failed" 
    }
  }
}

export async function registerWithOAuth(
  provider: string,
  authData: { code: string; state: string },
  customerData?: {
    first_name?: string
    last_name?: string
    phone?: string
  }
): Promise<{ success: boolean; customer?: any; error?: string }> {
  try {
    // First register with OAuth provider
    // Note: OAuth registration may work differently than email/password
    // For now, we'll use login flow for OAuth and handle registration on backend
    const token = await sdk.auth.login("customer", provider, authData)
    
    if (!token) {
      return { success: false, error: "Failed to authenticate with OAuth provider" }
    }
    
    await setAuthToken(token as string)
    
    const headers = {
      ...(await getAuthHeaders()),
    }
    
    // For OAuth, the customer should already be created by the authentication flow
    // Additional customer data can be updated via the update API if needed
    if (customerData) {
      try {
        // Try to update the customer profile with additional data
        const updatedCustomer = await updateCustomer(customerData)
        
        return { success: true, customer: updatedCustomer }
      } catch (customerError: any) {
        // If update fails, that's okay - proceed with basic OAuth login
        console.log("Customer profile update failed:", customerError.message)
      }
    }
    
    // Complete OAuth authentication
    const customerCacheTag = await getCacheTag("customers")
    revalidateTag(customerCacheTag)
    
    await transferCart()
    
    return { success: true }
  } catch (error: any) {
    console.error("OAuth registration error:", error)
    return { 
      success: false, 
      error: error.message || "OAuth authentication failed" 
    }
  }
}

"use client"

import { useState } from "react"
import { Button } from "@/components/atoms"
import { Modal } from "../Modal/Modal"
import { CustomerProfile } from "@/lib/data/customer"
import { cn } from "@/lib/utils"
import { toast } from "@/lib/helpers/toast"

interface PublicProfileProps {
  customerId: string
  initialProfile: CustomerProfile | null
}

export const PublicProfile = ({ customerId, initialProfile }: PublicProfileProps) => {
  const [showForm, setShowForm] = useState(false)
  const [profile, setProfile] = useState(initialProfile)
  const [displayName, setDisplayName] = useState(initialProfile?.display_name ?? "")
  const [bio, setBio] = useState(initialProfile?.bio ?? "")
  const [location, setLocation] = useState(initialProfile?.location ?? "")
  const [avatarFile, setAvatarFile] = useState<File | null>(null)
  const [avatarPreview, setAvatarPreview] = useState<string | null>(initialProfile?.avatar_url ?? null)
  const [isSaving, setIsSaving] = useState(false)
  const [error, setError] = useState<string | null>(null)

  const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0] ?? null
    setAvatarFile(file)
    if (file) setAvatarPreview(URL.createObjectURL(file))
  }

  const handleSave = async () => {
    if (!displayName.trim()) {
      setError("Display name is required")
      return
    }

    setError(null)
    setIsSaving(true)
    try {
      if (avatarFile) {
        const formData = new FormData()
        formData.append("avatar", avatarFile)
        await fetch(
          `${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/customers/${customerId}/profile/avatar`,
          { method: "POST", body: formData }
        )
      }

      const res = await fetch(
        `${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/customers/${customerId}/profile`,
        {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            display_name: displayName.trim(),
            bio: bio.trim() || undefined,
            location: location.trim() || undefined,
          }),
        }
      )

      if (!res.ok) {
        const err = await res.json()
        const message = err.message || "Failed to save profile"
        setError(message)
        toast.error({ title: message })
        return
      }

      const { data } = await res.json()
      setProfile((prev) => ({ ...prev!, ...data }))
      toast.success({ title: "Profile updated" })
      setShowForm(false)
    } catch {
      const message = "Failed to save profile. Please try again."
      setError(message)
      toast.error({ title: message })
    } finally {
      setIsSaving(false)
    }
  }

  const handleClose = () => {
    // Reset form to saved state
    setDisplayName(profile?.display_name ?? "")
    setBio(profile?.bio ?? "")
    setLocation(profile?.location ?? "")
    setAvatarFile(null)
    setAvatarPreview(profile?.avatar_url ?? null)
    setError(null)
    setShowForm(false)
  }

  return (
    <>
      <div
        className="rounded-[14px] overflow-hidden"
        style={{ background: "var(--bg-surface-1, #18162A)", border: "1px solid var(--border-default, #2C2A4A)" }}
      >
        <div
          className="flex justify-between items-center px-6 py-4"
          style={{ borderBottom: "1px solid var(--border-default, #2C2A4A)" }}
        >
          <h2
            className="font-barlow font-semibold"
            style={{ fontSize: 16, color: "var(--text-primary, #F0EEFF)" }}
          >
            Public Profile
          </h2>
          <button
            onClick={() => setShowForm(true)}
            className="text-sm font-medium rounded-[10px] px-4 py-2 transition-colors"
            style={{
              color: "var(--brand-primary, #8B5CF6)",
              border: "1px solid var(--brand-primary, #8B5CF6)",
              background: "transparent",
            }}
          >
            Edit
          </button>
        </div>
        <div className="px-6 py-4 space-y-4">
          <div className="flex items-center gap-4">
            <div
              className="w-12 h-12 rounded-full flex items-center justify-center overflow-hidden shrink-0"
              style={{ background: "var(--bg-surface-2, #21203A)", border: "1px solid var(--border-default, #2C2A4A)" }}
            >
              {profile?.avatar_url ? (
                // eslint-disable-next-line @next/next/no-img-element
                <img src={profile.avatar_url} alt="Avatar" className="w-full h-full object-cover" />
              ) : (
                <svg className="w-6 h-6" style={{ color: "var(--text-tertiary, #7B72A8)" }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                </svg>
              )}
            </div>
            <div>
              <p className="text-[13px] font-medium mb-1" style={{ color: "var(--text-secondary, #B8B0D8)" }}>Display name</p>
              <p className="text-sm" style={{ color: "var(--text-primary, #F0EEFF)" }}>
                {profile?.display_name || <span className="italic" style={{ color: "var(--text-tertiary, #7B72A8)" }}>Not set</span>}
              </p>
            </div>
          </div>
          <div style={{ borderTop: "1px solid var(--border-default, #2C2A4A)", paddingTop: 16 }}>
            <p className="text-[13px] font-medium mb-1" style={{ color: "var(--text-secondary, #B8B0D8)" }}>Bio</p>
            <p className="text-sm" style={{ color: "var(--text-primary, #F0EEFF)" }}>
              {profile?.bio || <span className="italic" style={{ color: "var(--text-tertiary, #7B72A8)" }}>Not set</span>}
            </p>
          </div>
          <div style={{ borderTop: "1px solid var(--border-default, #2C2A4A)", paddingTop: 16 }}>
            <p className="text-[13px] font-medium mb-1" style={{ color: "var(--text-secondary, #B8B0D8)" }}>Location</p>
            <p className="text-sm" style={{ color: "var(--text-primary, #F0EEFF)" }}>
              {profile?.location || <span className="italic" style={{ color: "var(--text-tertiary, #7B72A8)" }}>Not set</span>}
            </p>
          </div>
        </div>
      </div>

      {showForm && (
        <Modal heading="Edit public profile" onClose={handleClose}>
          <div className="space-y-4 p-4">
            {/* Avatar */}
            <div className="flex items-center gap-4">
              <div className="w-16 h-16 rounded-full bg-component flex items-center justify-center overflow-hidden border border-border shrink-0">
                {avatarPreview ? (
                  // eslint-disable-next-line @next/next/no-img-element
                  <img src={avatarPreview} alt="Avatar preview" className="w-full h-full object-cover" />
                ) : (
                  <svg className="w-7 h-7 text-secondary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
                  </svg>
                )}
              </div>
              <div>
                <label htmlFor="avatar-settings" className="cursor-pointer text-sm text-action hover:underline">
                  {avatarPreview ? "Change photo" : "Upload a photo"} (optional)
                </label>
                <p className="text-xs text-secondary mt-0.5">JPG, PNG or GIF · max 5 MB</p>
                <input id="avatar-settings" type="file" accept="image/*" className="sr-only" onChange={handleAvatarChange} />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-primary mb-1">
                Display name <span className="text-red-500">*</span>
              </label>
              <input
                type="text"
                value={displayName}
                onChange={(e) => setDisplayName(e.target.value)}
                maxLength={100}
                className="w-full px-3 py-2 bg-component border border-border rounded-lg text-primary focus:outline-none focus:ring-2 focus:ring-action"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-primary mb-1">
                Bio <span className="text-secondary font-normal">(optional)</span>
              </label>
              <textarea
                value={bio}
                onChange={(e) => setBio(e.target.value)}
                maxLength={2000}
                rows={3}
                className="w-full px-3 py-2 bg-component border border-border rounded-lg text-primary focus:outline-none focus:ring-2 focus:ring-action resize-none"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-primary mb-1">
                Location <span className="text-secondary font-normal">(optional)</span>
              </label>
              <input
                type="text"
                value={location}
                onChange={(e) => setLocation(e.target.value)}
                maxLength={255}
                className="w-full px-3 py-2 bg-component border border-border rounded-lg text-primary focus:outline-none focus:ring-2 focus:ring-action"
              />
            </div>

            {error && <p className="text-sm text-red-500">{error}</p>}

            <div className="flex justify-end gap-3 pt-2">
              <Button variant="tonal" onClick={handleClose}>Cancel</Button>
              <Button
                onClick={handleSave}
                disabled={isSaving}
                className={cn(isSaving && "opacity-50 cursor-not-allowed")}
              >
                {isSaving ? "Saving..." : "Save"}
              </Button>
            </div>
          </div>
        </Modal>
      )}
    </>
  )
}

