"use client"

import { HttpTypes } from "@medusajs/types"
import { CustomerProfile } from "@/lib/data/customer"

/** Game display config keyed by tcg_games values */
const GAME_CONFIG: Record<string, { label: string; colorVar: string; bgClass: string; borderClass: string }> = {
  mtg: {
    label: "MTG",
    colorVar: "var(--game-mtg, #A78BFA)",
    bgClass: "bg-[rgba(167,139,250,0.12)]",
    borderClass: "border-[rgba(167,139,250,0.25)]",
  },
  pokemon: {
    label: "Pokémon",
    colorVar: "var(--game-pokemon, #FCD34D)",
    bgClass: "bg-[rgba(252,211,77,0.10)]",
    borderClass: "border-[rgba(252,211,77,0.25)]",
  },
  yugioh: {
    label: "Yu-Gi-Oh!",
    colorVar: "var(--game-ygo, #60A5FA)",
    bgClass: "bg-[rgba(96,165,250,0.10)]",
    borderClass: "border-[rgba(96,165,250,0.25)]",
  },
  onepiece: {
    label: "One Piece",
    colorVar: "var(--game-optcg, #34D399)",
    bgClass: "bg-[rgba(52,211,153,0.10)]",
    borderClass: "border-[rgba(52,211,153,0.25)]",
  },
}

interface ProfileHeroProps {
  user: HttpTypes.StoreCustomer
  customerProfile: CustomerProfile | null
}

function getInitials(user: HttpTypes.StoreCustomer): string {
  const first = user.first_name?.[0] ?? ""
  const last = user.last_name?.[0] ?? ""
  if (first || last) return `${first}${last}`.toUpperCase()
  return (user.email?.[0] ?? "?").toUpperCase()
}

function getDisplayName(user: HttpTypes.StoreCustomer, profile: CustomerProfile | null): string {
  if (profile?.display_name) return profile.display_name
  const parts = [user.first_name, user.last_name].filter(Boolean)
  return parts.length > 0 ? parts.join(" ") : "User"
}

function getUsername(user: HttpTypes.StoreCustomer, profile: CustomerProfile | null): string {
  if (profile?.display_name) return `@${profile.display_name.toLowerCase().replace(/\s+/g, "")}`
  return `@${(user.email ?? "user").split("@")[0]}`
}

function formatJoinedDate(dateStr: string | undefined): string {
  if (!dateStr) return "Recently joined"
  const d = new Date(dateStr)
  return `Joined ${d.toLocaleDateString("en-US", { month: "long", year: "numeric" })}`
}

export function ProfileHero({ user, customerProfile }: ProfileHeroProps) {
  const initials = getInitials(user)
  const displayName = getDisplayName(user, customerProfile)
  const username = getUsername(user, customerProfile)
  const joinedDate = formatJoinedDate(user.created_at)
  const bio = customerProfile?.bio ?? null
  const games = customerProfile?.tcg_games ?? []

  return (
    <section
      className="relative h-[280px] md:h-[280px] overflow-hidden"
      style={{ background: "var(--bg-surface-1, #18162A)" }}
      data-testid="profile-hero"
    >
      {/* Radial gradient overlay */}
      <div
        className="absolute pointer-events-none"
        style={{
          top: -80,
          left: -120,
          width: 600,
          height: 400,
          background: "radial-gradient(ellipse, rgba(139,92,246,0.18) 0%, rgba(167,139,250,0.06) 40%, transparent 70%)",
