        <div className="flex flex-col md:flex-row items-center md:items-end gap-3 md:gap-6 flex-1 pb-4 md:pb-8">
          {/* Avatar */}
          <div className="relative shrink-0 translate-y-3 md:translate-y-6">
            <div
              className="w-[72px] h-[72px] md:w-[96px] md:h-[96px] rounded-full flex items-center justify-center font-barlow-condensed font-bold text-white"
              style={{
                background: "linear-gradient(135deg, var(--brand-primary, #8B5CF6), #A78BFA, var(--brand-secondary, #FF7849))",
                border: "3px solid var(--brand-primary, #8B5CF6)",
                boxShadow: "0 0 24px rgba(139,92,246,0.35), 0 0 48px rgba(139,92,246,0.15)",
                fontSize: "clamp(28px, 4vw, 36px)",
                textShadow: "0 2px 8px rgba(0,0,0,0.3)",
              }}
              data-testid="profile-avatar"
            >
              {initials}
            </div>
            {/* Online status dot */}
            <div
              className="absolute bottom-1 right-1 w-4 h-4 rounded-full"
