"use client"

import { useEffect, useState, type ReactNode } from "react"

export type ProfileTabId = "collection" | "decks" | "activity" | "settings"

const TABS: { id: ProfileTabId; label: string }[] = [
  { id: "collection", label: "Collection" },
  { id: "decks", label: "Decks" },
  { id: "activity", label: "Activity" },
  { id: "settings", label: "Settings" },
]

interface ProfileTabsProps {
  children: Record<ProfileTabId, ReactNode>
}

function readHash(): ProfileTabId {
  if (typeof window === "undefined") return "collection"
  const raw = window.location.hash.replace("#", "").toLowerCase()
  if (TABS.some((t) => t.id === raw)) return raw as ProfileTabId
  return "collection"
}

export function ProfileTabs({ children }: ProfileTabsProps) {
  const [activeTab, setActiveTab] = useState<ProfileTabId>("collection")

  useEffect(() => {
    // Read initial hash
    setActiveTab(readHash())

    const onHashChange = () => setActiveTab(readHash())
    window.addEventListener("hashchange", onHashChange)
    return () => window.removeEventListener("hashchange", onHashChange)
  }, [])

  const handleTabClick = (id: ProfileTabId) => {
    window.location.hash = `#${id}`
    setActiveTab(id)
  }

  return (
    <div className="max-w-[1200px] mx-auto mt-10 px-5 md:px-12">
      {/* Tab bar */}
      <div
        className="flex overflow-x-auto mb-6 md:mb-8"
        style={{ borderBottom: "1px solid var(--border-default, #2C2A4A)" }}
        role="tablist"
        data-testid="profile-tab-bar"
      >
        {TABS.map((tab) => {
          const isActive = activeTab === tab.id
          return (
            <button
              key={tab.id}
              role="tab"
              aria-selected={isActive}
              onClick={() => handleTabClick(tab.id)}
              className="relative font-barlow text-sm font-semibold whitespace-nowrap px-4 md:px-6 py-3 transition-colors shrink-0"
              style={{
                color: isActive
                  ? "var(--brand-primary, #8B5CF6)"
                  : "var(--text-tertiary, #7B72A8)",
              }}
              data-testid={`tab-${tab.id}`}
            >
              {tab.label}
              {isActive && (
                <span
                  className="absolute bottom-[-1px] left-0 right-0 h-0.5 rounded-t-sm"
                  style={{ background: "var(--brand-primary, #8B5CF6)" }}
                />
              )}
            </button>
          )
        })}
      </div>

      {/* Tab content */}
      <div data-testid={`tab-content-${activeTab}`}>
        {children[activeTab]}
      </div>
    </div>
  )
}

export function DecksTabContent() {
  return (
    <div className="flex flex-col items-center justify-center py-20 text-center" data-testid="decks-empty-state">
