        className="text-sm max-w-sm"
        style={{ color: "var(--text-tertiary, #7B72A8)" }}
      >
        Decks you create will be displayed here. Build and share your favorite strategies.
      </p>
    </div>
  )
}

export function ActivityTabContent() {
  return (
    <div className="flex flex-col items-center justify-center py-20 text-center" data-testid="activity-empty-state">
      {/* Activity/clock icon */}
      <svg
        className="w-12 h-12 mb-4"
        style={{ color: "var(--text-tertiary, #7B72A8)" }}
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth={1.5}
