import { ProfilePage } from "../ProfilePage"
import { ProfileHero } from "../ProfileHero"
import { ProfileTabs } from "../ProfileTabs"
import { CollectionTabContent } from "../tabs/CollectionTabContent"
import { DecksTabContent } from "../tabs/DecksTabContent"
import { ActivityTabContent } from "../tabs/ActivityTabContent"
import type { HttpTypes } from "@medusajs/types"
import type { CustomerProfile } from "@/lib/data/customer"

// --- Test fixtures ---
const mockUser: HttpTypes.StoreCustomer = {
  id: "cust_test123",
  email: "alex@example.com",
  first_name: "Alex",
  last_name: "Chen",
  phone: "+1234567890",
  created_at: "2025-03-15T00:00:00.000Z",
  has_account: true,
  addresses: [],
  metadata: {},
} as any

const mockProfile: CustomerProfile = {
  customer_id: "cust_test123",
  display_name: "Alex Chen",
  bio: "Competitive MTG player. Modern & Legacy enthusiast.",
  location: "New York",
  avatar_url: null,
  tcg_games: ["mtg", "pokemon", "yugioh"],
  notify_order_updates: true,
  notify_price_alerts: true,
  notify_messages: true,
  profile_public: true,
  show_sales_history: true,
  is_seller: false,
}

const mockRegions: HttpTypes.StoreRegion[] = []

beforeEach(() => {
  // Clear hash between tests
  window.location.hash = ""
})

// ─── ProfileHero tests ───────────────────────────────────────────────

describe("ProfileHero", () => {
  it("renders avatar with initials from first_name and last_name", () => {
    render(<ProfileHero user={mockUser} customerProfile={null} />)
    const avatar = screen.getByTestId("profile-avatar")
    expect(avatar.textContent).toBe("AC")
  })

  it("renders display name from profile when available", () => {
    render(<ProfileHero user={mockUser} customerProfile={mockProfile} />)
    expect(screen.getByTestId("profile-display-name").textContent).toBe("Alex Chen")
  })

  it("falls back to user first_name + last_name when no profile display_name", () => {
    render(<ProfileHero user={mockUser} customerProfile={null} />)
    expect(screen.getByTestId("profile-display-name").textContent).toBe("Alex Chen")
  })

  it("renders username derived from display_name", () => {
    render(<ProfileHero user={mockUser} customerProfile={mockProfile} />)
    expect(screen.getByTestId("profile-username").textContent).toBe("@alexchen")
  })

  it("falls back to email prefix for username when no display_name", () => {
    render(<ProfileHero user={mockUser} customerProfile={null} />)
    expect(screen.getByTestId("profile-username").textContent).toBe("@alex")
  })

  it("renders game badges with correct game labels", () => {
    render(<ProfileHero user={mockUser} customerProfile={mockProfile} />)
    const badges = screen.getByTestId("game-badges")
    expect(badges).toBeTruthy()
    expect(screen.getByTestId("game-badge-mtg").textContent).toBe("MTG")
    expect(screen.getByTestId("game-badge-pokemon").textContent).toBe("Pokémon")
    expect(screen.getByTestId("game-badge-yugioh").textContent).toBe("Yu-Gi-Oh!")
  })

  it("renders game badges with correct game-specific colors", () => {
    render(<ProfileHero user={mockUser} customerProfile={mockProfile} />)
    const mtgBadge = screen.getByTestId("game-badge-mtg")
    expect(mtgBadge.style.color).toContain("--game-mtg")
    const pokemonBadge = screen.getByTestId("game-badge-pokemon")
    expect(pokemonBadge.style.color).toContain("--game-pokemon")
    const ygoBadge = screen.getByTestId("game-badge-yugioh")
    expect(ygoBadge.style.color).toContain("--game-ygo")
  })

  it("renders stat chips for cards, decks, trades, and rating", () => {
    render(<ProfileHero user={mockUser} customerProfile={mockProfile} />)
    const chips = screen.getByTestId("stat-chips")
    expect(chips).toBeTruthy()
    expect(screen.getByTestId("stat-chip-cards")).toBeTruthy()
    expect(screen.getByTestId("stat-chip-decks")).toBeTruthy()
    expect(screen.getByTestId("stat-chip-trades")).toBeTruthy()
    expect(screen.getByTestId("stat-chip-rating")).toBeTruthy()
  })

  it("uses smaller avatar class on mobile (72px)", () => {
    render(<ProfileHero user={mockUser} customerProfile={mockProfile} />)
    const avatar = screen.getByTestId("profile-avatar")
    // Mobile-first: w-[72px] h-[72px], desktop: md:w-[96px] md:h-[96px]
    expect(avatar.className).toContain("w-[72px]")
    expect(avatar.className).toContain("h-[72px]")
    expect(avatar.className).toContain("md:w-[96px]")
    expect(avatar.className).toContain("md:h-[96px]")
  })

  it("renders joined date from created_at", () => {
    render(<ProfileHero user={mockUser} customerProfile={null} />)
    expect(screen.getByText("Joined March 2025")).toBeTruthy()
  })

  it("renders bio when present", () => {
    render(<ProfileHero user={mockUser} customerProfile={mockProfile} />)
    expect(screen.getByText("Competitive MTG player. Modern & Legacy enthusiast.")).toBeTruthy()
  })
})

// ─── ProfileTabs tests ──────────────────────────────────────────────

describe("ProfileTabs", () => {
  const tabContent = {
    collection: <div data-testid="content-collection">Collection Content</div>,
    decks: <div data-testid="content-decks">Decks Content</div>,
    activity: <div data-testid="content-activity">Activity Content</div>,
    settings: <div data-testid="content-settings">Settings Content</div>,
  }

  it("renders 4 tab buttons", () => {
    render(<ProfileTabs>{tabContent}</ProfileTabs>)
    const tabBar = screen.getByTestId("profile-tab-bar")
    const tabs = tabBar.querySelectorAll("[role='tab']")
    expect(tabs.length).toBe(4)
  })

  it("defaults to collection tab", () => {
    render(<ProfileTabs>{tabContent}</ProfileTabs>)
    expect(screen.getByTestId("content-collection")).toBeTruthy()
  })

  it("switches tab when clicking a tab button", () => {
    render(<ProfileTabs>{tabContent}</ProfileTabs>)
    fireEvent.click(screen.getByTestId("tab-settings"))
    expect(screen.getByTestId("content-settings")).toBeTruthy()
  })

  it("sets aria-selected on active tab", () => {
    render(<ProfileTabs>{tabContent}</ProfileTabs>)
    expect(screen.getByTestId("tab-collection").getAttribute("aria-selected")).toBe("true")
    expect(screen.getByTestId("tab-settings").getAttribute("aria-selected")).toBe("false")
  })
})

// ─── Tab content empty states ───────────────────────────────────────

describe("CollectionTabContent", () => {
  it("renders empty state message", () => {
    render(<CollectionTabContent />)
    expect(screen.getByText("Your collection will appear here")).toBeTruthy()
  })
})

describe("DecksTabContent", () => {
  it("renders empty state message", () => {
    render(<DecksTabContent />)
    expect(screen.getByText("Your decks will appear here")).toBeTruthy()
  })
})

describe("ActivityTabContent", () => {
  it("renders empty state message", () => {
    render(<ActivityTabContent />)
    expect(screen.getByText("Your activity will appear here")).toBeTruthy()
  })
})

// ─── ProfilePage integration tests ──────────────────────────────────

describe("ProfilePage", () => {
  it("renders hero and tab bar", () => {
    render(
      <ProfilePage user={mockUser} customerProfile={mockProfile} regions={mockRegions} />
    )
    expect(screen.getByTestId("profile-hero")).toBeTruthy()
    expect(screen.getByTestId("profile-tab-bar")).toBeTruthy()
  })

  it("shows Settings tab content with ProfileDetails heading when settings tab is clicked", () => {
    render(
      <ProfilePage user={mockUser} customerProfile={mockProfile} regions={mockRegions} />
    )
    fireEvent.click(screen.getByTestId("tab-settings"))
    expect(screen.getByTestId("profile-details")).toBeTruthy()
    expect(screen.getByTestId("public-profile")).toBeTruthy()
    expect(screen.getByTestId("user-preferences")).toBeTruthy()
    expect(screen.getByTestId("addresses")).toBeTruthy()
    expect(screen.getByTestId("profile-password")).toBeTruthy()
    expect(screen.getByTestId("security-settings")).toBeTruthy()
  })

  it("shows collection empty state on default tab", () => {
    render(
      <ProfilePage user={mockUser} customerProfile={mockProfile} regions={mockRegions} />
    )
    expect(screen.getByText("Your collection will appear here")).toBeTruthy()
  })
})

// ─── Voltage token compliance ───────────────────────────────────────

describe("Voltage token compliance", () => {
  it("has no Tailwind gray classes in ProfileHero", () => {
    const { container } = render(<ProfileHero user={mockUser} customerProfile={mockProfile} />)
    const html = container.innerHTML
    expect(html).not.toMatch(/bg-white|bg-gray-|text-gray-/)
  })

  it("has no Tailwind gray classes in ProfilePage", () => {
    const { container } = render(
      <ProfilePage user={mockUser} customerProfile={mockProfile} regions={mockRegions} />
    )
    const html = container.innerHTML
    expect(html).not.toMatch(/bg-white|bg-gray-|text-gray-/)
  })
})

